(function () {
  const nodes = document.querySelectorAll("[data-i18n]");
  const defaults = {};
  nodes.forEach((n) => { defaults[n.getAttribute("data-i18n")] = n.innerHTML; });

  function apply(lang) {
    const dict = I18N[lang];
    nodes.forEach((n) => {
      const key = n.getAttribute("data-i18n");
      n.innerHTML = dict && dict[key] != null ? dict[key] : defaults[key];
    });
    document.documentElement.lang = lang;
    try { localStorage.setItem("site-lang", lang); } catch (e) {}
    const sel = document.getElementById("lang-select");
    if (sel) sel.value = lang;
  }

  let initial = "en";
  try {
    const saved = localStorage.getItem("site-lang");
    if (saved && (saved === "en" || I18N[saved])) initial = saved;
    else {
      const nav = (navigator.language || "en").slice(0, 2).toLowerCase();
      if (nav === "en" || I18N[nav]) initial = nav;
    }
  } catch (e) {}

  const sel = document.getElementById("lang-select");
  if (sel) sel.addEventListener("change", (e) => apply(e.target.value));

  if (initial !== "en") apply(initial);
  else if (sel) sel.value = "en";

  window.__applyLang = apply;
})();
